import os, json

# Copy datasets from geometry-of-truth repo
os.makedirs("datasets/geometry_of_truth", exist_ok=True)
src = "code/geometry-of-truth/datasets"
if os.path.exists(src):
    import shutil
    for f in os.listdir(src):
        shutil.copy2(os.path.join(src, f), "datasets/geometry_of_truth/")
    print(f"Copied geometry-of-truth datasets: {os.listdir('datasets/geometry_of_truth')}")

# Copy datasets from Truth_is_Universal repo
os.makedirs("datasets/truth_is_universal", exist_ok=True)
src2 = "code/Truth_is_Universal/datasets"
if os.path.exists(src2):
    for f in os.listdir(src2):
        src_path = os.path.join(src2, f)
        if os.path.isfile(src_path):
            import shutil
            shutil.copy2(src_path, "datasets/truth_is_universal/")
    print(f"Copied Truth_is_Universal datasets: {os.listdir('datasets/truth_is_universal')[:10]}")

# Check LLM-LieDetector for datasets
lie_data = "code/LLM-LieDetector"
if os.path.exists(lie_data):
    for root, dirs, files in os.walk(lie_data):
        for f in files:
            if f.endswith(('.csv', '.json', '.jsonl', '.tsv', '.pkl')):
                print(f"  LieDetector data: {os.path.join(root, f)}")

print("\nDone!")
PYEOF
